#include <stdio.h>
#include <stdlib.h>
#include <time.h>
#include <assert.h>
#include <iostream>
#include <omp.h>
#include <cstring>

using namespace std;

#define HALO     1
#define STR_SIZE 256
#define M_SEED   9

#define IN_RANGE(x, min, max) ((x)>= (min) && (x)<= (max))
#define CLAMP_RANGE(x, min, max) x = (x<(min)) ? min : ((x>(max)) ? max : x )
#define MIN(a, b) ((a)<= (b) ? (a) : (b))

int   rows = -1, cols = -1;
int   Ne = rows * cols;
int*  my_data;
int** wall;
int*  result;
int   pyramid_height = -1;
int   verbose = 0;

#ifdef TIMING
struct timeval tv;
struct timeval tv_total_start, tv_total_end;
struct timeval tv_init_end;
struct timeval tv_h2d_start, tv_h2d_end;
struct timeval tv_d2h_start, tv_d2h_end;
struct timeval tv_kernel_start, tv_kernel_end;
struct timeval tv_mem_alloc_start, tv_mem_alloc_end;
struct timeval tv_close_start, tv_close_end;
float init_time = 0, mem_alloc_time = 0, h2d_time = 0, kernel_time = 0,
      d2h_time = 0, close_time = 0, total_time = 0;

void tvsub(struct timeval *tsub, struct timeval *t0, struct timeval *t1) {
    tsub->tv_sec = t1->tv_sec - t0->tv_sec;
    tsub->tv_usec = t1->tv_usec - t0->tv_usec;
    if (tsub->tv_usec < 0) {
        tsub->tv_sec--;
        tsub->tv_usec += 1000000;
    }
}
#endif

void init(int argc, char** argv)
{
    int cur_arg;
    for (cur_arg = 1; cur_arg<argc; cur_arg++) {
        if (strcmp(argv[cur_arg], "-c") == 0) {
            if (argc >= cur_arg + 1) {
                cols = atoi(argv[cur_arg+1]);
                cur_arg++;
            }
        }
        else if (strcmp(argv[cur_arg], "-r") == 0) {
            if (argc >= cur_arg + 1) {
                rows = atoi(argv[cur_arg+1]);
                cur_arg++;
            }
        }
        else if (strcmp(argv[cur_arg], "-h") == 0) {
            if (argc >= cur_arg + 1) {
                pyramid_height = atoi(argv[cur_arg+1]);
                cur_arg++;
            }
        }
        if (strcmp(argv[cur_arg], "-v") == 0) {
            verbose = 1;
        }
    }

    if (cols < 0 || rows < 0 || pyramid_height < 0)
    {
        fprintf(stderr, "usage: %s <-r rows> <-c cols> <-h pyramid_height> [-v]\n", argv[0]);
        exit(0);
    }
    my_data = new int[rows * cols];
    wall = new int*[rows];
    for (int n = 0; n < rows; n++)
    {
        wall[n] = my_data + cols * n;
    }
    result = new int[cols];

    int seed = M_SEED;
    srand(seed);

    for (int i = 0; i < rows; i++)
    {
        for (int j = 0; j < cols; j++)
        {
            wall[i][j] = rand() % 10;
        }
    }
#ifdef BENCH_PRINT
    for (int i = 0; i < rows; i++)
    {
        for (int j = 0; j < cols; j++)
        {
            printf("%d ", wall[i][j]);
        }
        printf("\n");
    }
#endif
}

void fatal(char *s)
{
    fprintf(stderr, "error: %s\n", s);
}

// Simulated OpenCL local size behavior for the algorithm
const int BLOCK_SIZE = 256; 

void dynproc_kernel (int iteration,
                     int* gpuWall,
                     int* gpuSrc,
                     int* gpuResults,
                     int cols,
                     int rows,
                     int startStep,
                     int border,
                     int HALO_val,
                     int* prev,
                     int* result_arr,
                     int* outputBuffer,
                     int bx)
{
    int small_block_cols = BLOCK_SIZE - (iteration*HALO_val*2);
    if (small_block_cols < 1) small_block_cols = 1;

    int blkX = (small_block_cols*bx) - border;
    int blkXmax = blkX+BLOCK_SIZE-1;

    int validXmin = (blkX < 0) ? -blkX : 0;
    int validXmax = (blkXmax > cols-1) ? BLOCK_SIZE-1-(blkXmax-cols+1) : BLOCK_SIZE-1;

    // Parallel execution over threads within the block
    #pragma omp parallel
    {
        int tx = omp_get_thread_num();
        if (tx >= BLOCK_SIZE) return;

        int xidx = blkX + tx;

        int W = tx-1;
        int E = tx+1;

        W = (W < validXmin) ? validXmin : W;
        E = (E > validXmax) ? validXmax : E;

        bool isValid = IN_RANGE(tx, validXmin, validXmax);

        if(IN_RANGE(xidx, 0, cols-1))
        {
            prev[tx] = gpuSrc[xidx];
        }

        #pragma omp barrier

        bool computed = false;

        for (int i = 0; i < iteration; i++)
        {
            computed = false;

            if( IN_RANGE(tx, i+1, BLOCK_SIZE-i-2) && isValid )
            {
                computed = true;
                int left = prev[W];
                int up = prev[tx];
                int right = prev[E];
                int shortest = MIN(left, up);
                shortest = MIN(shortest, right);

                int index = cols*(startStep+i)+xidx;
                result_arr[tx] = shortest + gpuWall[index];

                if (tx==11 && i==0)
                {
                    int bufIndex = gpuSrc[xidx];
                    if (bufIndex >= 0 && bufIndex < 16384) {
                        outputBuffer[bufIndex] = 1;
                    }
                }
            }

            #pragma omp barrier

            if(i==iteration-1)
            {
                break;
            }

            if(computed)
            {
                prev[tx] = result_arr[tx];
            }
            #pragma omp barrier
        }

        if (computed)
        {
            if (IN_RANGE(xidx, 0, cols-1)) {
                gpuResults[xidx] = result_arr[tx];
            }
        }
    }
}

int main(int argc, char** argv)
{
    init(argc, argv);

    int borderCols = (pyramid_height) * HALO;

    int size = rows * cols;

#ifdef  TIMING
    gettimeofday(&tv_total_start, NULL);
#endif

#ifdef  TIMING
    gettimeofday(&tv_init_end, NULL);
    tvsub(&tv_init_end, &tv_total_start, &tv);
    init_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

    int* h_outputBuffer = (int*)malloc(16384 * sizeof(int));
    for (int i = 0; i < 16384; i++) {
        h_outputBuffer[i] = 0;
    }

#ifdef  TIMING
    gettimeofday(&tv_mem_alloc_start, NULL);
#endif

    // Simulated buffers
    int* d_gpuWall = new int[size - cols];
    int* d_gpuResult[2];
    d_gpuResult[0] = new int[cols];
    d_gpuResult[1] = new int[cols];
    int* d_outputBuffer = new int[16384];

    // Copy initial data
    for(int i=0; i<size-cols; ++i) d_gpuWall[i] = my_data[i+cols];
    for(int i=0; i<cols; ++i) d_gpuResult[0][i] = my_data[i];
    for(int i=0; i<cols; ++i) d_gpuResult[1][i] = 0;
    for(int i=0; i<16384; ++i) d_outputBuffer[i] = h_outputBuffer[i];

#ifdef  TIMING
    gettimeofday(&tv_mem_alloc_end, NULL);
    tvsub(&tv_mem_alloc_end, &tv_mem_alloc_start, &tv);
    mem_alloc_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

#ifdef TIMING
    gettimeofday(&tv_h2d_start, NULL);
    gettimeofday(&tv_h2d_end, NULL);
    tvsub(&tv_h2d_end, &tv_h2d_start, &tv);
    h2d_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

    int src = 1, final_ret = 0;

    // Determine number of blocks needed
    int small_block_cols_base = BLOCK_SIZE - (pyramid_height*HALO*2);
    if (small_block_cols_base <= 0) small_block_cols_base = 1; 
    int num_blocks = (cols + 2*borderCols + small_block_cols_base - 1) / small_block_cols_base;

    // Allocate local buffers for each block
    int* all_prev = new int[num_blocks * BLOCK_SIZE];
    int* all_result = new int[num_blocks * BLOCK_SIZE];

    for (int t = 0; t < rows - 1; t += pyramid_height)
    {
        int temp = src;
        src = final_ret;
        final_ret = temp;

        int arg0 = MIN(pyramid_height, rows-t-1);
        int theHalo = HALO;

#ifdef TIMING
        gettimeofday(&tv_kernel_start, NULL);
#endif

        #pragma omp parallel for
        for (int bx = 0; bx < num_blocks; bx++) {
            int* local_prev = all_prev + bx * BLOCK_SIZE;
            int* local_result = all_result + bx * BLOCK_SIZE;

            dynproc_kernel (arg0,
                          d_gpuWall,
                          d_gpuResult[src],
                          d_gpuResult[final_ret],
                          cols,
                          rows,
                          t,
                          borderCols,
                          theHalo,
                          local_prev,
                          local_result,
                          d_outputBuffer,
                          bx);
        }

#ifdef TIMING
        gettimeofday(&tv_kernel_end, NULL);
        tvsub(&tv_kernel_end, &tv_kernel_start, &tv);
        kernel_time += tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif
    }

#ifdef TIMING
    gettimeofday(&tv_d2h_start, NULL);
#endif

    // Copy result back
    for(int i=0; i<cols; ++i) result[i] = d_gpuResult[final_ret][i];
    for(int i=0; i<16384; ++i) h_outputBuffer[i] = d_outputBuffer[i];

#ifdef TIMING
    gettimeofday(&tv_d2h_end, NULL);
    tvsub(&tv_d2h_end, &tv_d2h_start, &tv);
    d2h_time += tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

    h_outputBuffer[16383] = '\0';

#ifdef BENCH_PRINT
    for (int i = 0; i < cols; i++)
        printf("%d ", my_data[i]);
    printf("\n");
    for (int i = 0; i < cols; i++)
        printf("%d ", result[i]);
    printf("\n");
#endif

#ifdef  TIMING
    gettimeofday(&tv_close_start, NULL);
#endif

    delete[] d_gpuWall;
    delete[] d_gpuResult[0];
    delete[] d_gpuResult[1];
    delete[] d_outputBuffer;
    delete[] all_prev;
    delete[] all_result;

#ifdef  TIMING
    gettimeofday(&tv_close_end, NULL);
    tvsub(&tv_close_end, &tv_close_start, &tv);
    close_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

    delete[] my_data;
    delete[] wall;
    delete[] result;
    free(h_outputBuffer);

    return EXIT_SUCCESS;
}
